            aOrbiterE = ((aOrbiterE + aOrbiterD) + 0x5D107578B12D4B75ULL) + aPhaseDOrbiterUpdateSaltD[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterG = (aOrbiterG ^ aOrbiterE) ^ 0x54A7E8F17C2B2E33ULL;
            aOrbiterG = RotL64((aOrbiterG * 0xC4BB665E25141B2DULL), 27U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterF) + 0x9550B4EEC9896535ULL) + aPhaseDOrbiterUpdateSaltA[(((31U - aIndex) + 17U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterA) ^ 0xB5DD2F38EEF931ECULL;
            aOrbiterE = RotL64((aOrbiterE * 0x23933F1D9F348195ULL), 57U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterC) + 0x6453AC904A540590ULL;
            aOrbiterF = ((aOrbiterF ^ aOrbiterG) ^ 0xC31EB835CBF1CCF3ULL) ^ aPhaseDOrbiterUpdateSaltF[(((31U - aIndex) + 13U)) & S_SALT1];
            aOrbiterF = RotL64((aOrbiterF * 0xA429B855691D6881ULL), 35U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterJ) + 0xCE5C335DAC7D969AULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterC) ^ 0xE20DB7F1B42DA134ULL;
            aOrbiterI = RotL64((aOrbiterI * 0x48F26F63175243DFULL), 5U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterG) + 0x9BC5FAC2C5482F5AULL;
            aOrbiterA = ((aOrbiterA ^ aOrbiterJ) ^ 0x84142703753D0336ULL) ^ aPhaseDOrbiterUpdateSaltB[(((31U - aIndex) + 16U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0xD59CD3EFBA49D629ULL), 11U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterA) + 0xD01DC55D7C569B5DULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterI) ^ 0x58541ADC190B0667ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x91DE22FD9457C7B9ULL), 47U);
            //
            aIngress = aOrbiterG ^ RotL64(aOrbiterB, 36U);
