            //
            aScatter = (RotL64(aPrevious, 19U) + RotL64(aCross, 57U)) ^ (RotL64(aCarry, 5U) + RotL64(aIngress, 38U));
            aScatter = TwistMix64::DiffuseB(aScatter);
            //
            aOrbiterF = ((aWandererD + RotL64(aCross, 29U)) + RotL64(aCarry, 23U)) + 0x2F297EEEBDB1A815ULL;
            aOrbiterG = (aWandererJ + RotL64(aScatter, 54U)) + 0xDA0FC0D37AD5F438ULL;
            aOrbiterH = (aWandererI + RotL64(aIngress, 43U)) + 0xF18A4CD4FCF94DE8ULL;
            aOrbiterC = (((aWandererG + RotL64(aPrevious, 21U)) + RotL64(aCarry, 53U)) + 0x612055B720EA386AULL) + aPhaseGOrbiterAssignSaltE[((aIndex + 17U)) & S_SALT1];
            aOrbiterA = (aWandererC + RotL64(aScatter, 19U)) + 0x7E59A79BC416740AULL;
            aOrbiterI = (((aWandererE + RotL64(aIngress, 26U)) + RotL64(aCarry, 47U)) + 0x8322D1DC7ED1FCC5ULL) + aPhaseGOrbiterAssignSaltA[(((31U - aIndex) + 16U)) & S_SALT1];
            aOrbiterK = (aWandererK + RotL64(aCross, 23U)) + 0xF42C925AFE8EF0DDULL;
            aOrbiterD = (aWandererA + RotL64(aPrevious, 51U)) + 0x3ED4AB3E2FEAA3D8ULL;
            aOrbiterB = (aWandererB + RotL64(aCross, 41U)) + 0x519AB81423F348D5ULL;
            aOrbiterE = (aWandererH + RotL64(aPrevious, 37U)) + 0x799E152D91523348ULL;
            aOrbiterJ = (aWandererF + RotL64(aScatter, 11U)) + 0x7B231A32B551E468ULL;
            //
            aOrbiterF = (aOrbiterF + aOrbiterG) + 0xAAA5F98DC6D4C89DULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterF) ^ 0x1DE4E6E76161A9A4ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x65ED1D8392A5A835ULL), 39U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterH) + 0xDF0E96323375B186ULL;
            aOrbiterA = (aOrbiterA ^ aOrbiterC) ^ 0x72AEDC9056CCC17BULL;
            aOrbiterA = RotL64((aOrbiterA * 0xBD4304DEFC7D7EBFULL), 3U);
            //
            aOrbiterI = (aOrbiterI + aOrbiterK) + 0x568ACC6C2DE47D32ULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterI) ^ 0xC9DCF0135DD682A3ULL;
            aOrbiterD = RotL64((aOrbiterD * 0xF0E4330262AE9EFDULL), 47U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterA) + 0x3FA7DDE3198E7635ULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterK) ^ 0x251542EDCDAF96A0ULL;
            aOrbiterB = RotL64((aOrbiterB * 0x22B393C5C0C1B7C7ULL), 19U);
            //
            aOrbiterG = (aOrbiterG + aOrbiterE) + 0x253BB4213BF3A736ULL;
            aOrbiterI = (aOrbiterI ^ aOrbiterG) ^ 0xA30CE3916B3E24FEULL;
            aOrbiterI = RotL64((aOrbiterI * 0x8C80987039541C57ULL), 13U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterJ) + 0x427408547156C23EULL) + aPhaseGOrbiterUpdateSaltD[(((31U - aIndex) + 29U)) & S_SALT1];
            aOrbiterF = (aOrbiterF ^ aOrbiterA) ^ 0xC39D09EF729CBA02ULL;
            aOrbiterF = RotL64((aOrbiterF * 0x64D055F8C1F4B333ULL), 41U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterC) + 0x7F2D3D2BBE664D2EULL;
            aOrbiterK = (aOrbiterK ^ aOrbiterE) ^ 0xE5F9681D33517948ULL;
            aOrbiterK = RotL64((aOrbiterK * 0xA7CF52CBC1E9810FULL), 35U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterI) + 0xAFC1E365DDD8AD75ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterH) ^ 0xF944A6312B466965ULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x22D6F60578FCDA13ULL), 51U);
            //
            aOrbiterJ = ((aOrbiterJ + aOrbiterD) + 0x1B7CDAB864207E2EULL) + aPhaseGOrbiterUpdateSaltA[(((31U - aIndex) + 11U)) & S_SALT1];
            aOrbiterG = ((aOrbiterG ^ aOrbiterJ) ^ 0xAB8A84FB0CC14D08ULL) ^ aPhaseGOrbiterUpdateSaltE[(((31U - aIndex) + 13U)) & S_SALT1];
