            aOrbiterC = (aOrbiterC ^ aOrbiterB) ^ 0x57D4FEE95CFBEDDAULL;
            aOrbiterC = RotL64((aOrbiterC * 0x7656A9D2E68D7315ULL), 53U);
            //
            aOrbiterD = ((aOrbiterD + aOrbiterB) + 0x4E36A1B788D60DA9ULL) + aPhaseGOrbiterUpdateSaltF[((aIndex + 12U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterD) ^ 0x5281CBCAB65A652EULL;
