            aOrbiterA = ((aOrbiterA ^ aOrbiterB) ^ 0xE5B6E91F27A6F5BDULL) ^ aPhaseGOrbiterUpdateSaltF[(((31U - aIndex) + 9U)) & S_SALT1];
            aOrbiterA = RotL64((aOrbiterA * 0xB84B08083035954DULL), 3U);
