            aWandererK = aWandererK ^ ((RotL64(aScatter, 3U) + RotL64(aOrbiterC, 28U)) + aOrbiterB);
            aWandererG = aWandererG + (((RotL64(aCross, 58U) + aOrbiterI) + RotL64(aOrbiterK, 43U)) + RotL64(aCarry, 11U));
