            aWandererE = aWandererE + (((RotL64(aIngress, 35U) + RotL64(aOrbiterK, 41U)) + aOrbiterA) + RotL64(aCarry, 41U));
            aWandererJ = aWandererJ ^ ((RotL64(aCross, 19U) + RotL64(aOrbiterF, 58U)) + aOrbiterA);
            aWandererB = aWandererB + (((RotL64(aScatter, 27U) + RotL64(aOrbiterG, 5U)) + aOrbiterJ) + aPhaseGWandererUpdateSaltD[(((31U - aIndex) + 13U)) & S_SALT1]);
