            aWandererD = aWandererD + ((RotL64(aIngress, 23U) + aOrbiterI) + RotL64(aOrbiterJ, 23U));
            aWandererH = aWandererH ^ ((RotL64(aScatter, 5U) + aOrbiterI) + RotL64(aOrbiterG, 3U));
