            aOrbiterE = (((aWandererI + RotL64(aIngress, 35U)) + RotL64(aCarry, 43U)) + 0xB45B662A41171D5BULL) + aPhaseHOrbiterAssignSaltC[((aIndex + 29U)) & S_SALT1];
            aOrbiterH = ((aWandererA + RotL64(aScatter, 29U)) + RotL64(aCarry, 57U)) + 0x654F5CD3548F0B4BULL;
