            aOrbiterB = (aWandererK + RotL64(aCross, 23U)) + 0x737DB61D8F23B169ULL;
            //
            aOrbiterD = (aOrbiterD + aOrbiterE) + 0x781393852F4BF89EULL;
            aOrbiterH = (aOrbiterH ^ aOrbiterD) ^ 0x914270F56D168203ULL;
            aOrbiterH = RotL64((aOrbiterH * 0x4D3269D576A3C343ULL), 41U);
            //
            aOrbiterA = (aOrbiterA + aOrbiterJ) + 0x78C150EA8F3607E1ULL;
            aOrbiterC = (aOrbiterC ^ aOrbiterA) ^ 0x485F20C3EC84AD27ULL;
            aOrbiterC = RotL64((aOrbiterC * 0x38831E4B5213993DULL), 27U);
            //
            aOrbiterE = (aOrbiterE + aOrbiterC) + 0xB2C4E308520CBB27ULL;
            aOrbiterG = ((aOrbiterG ^ aOrbiterE) ^ 0x1E1EE6EF62D810D2ULL) ^ aPhaseHOrbiterUpdateSaltA[((aIndex + 20U)) & S_SALT1];
            aOrbiterG = RotL64((aOrbiterG * 0x9A16953C14BACB37ULL), 5U);
            //
            aOrbiterK = ((aOrbiterK + aOrbiterA) + 0x8FA20AE913D94F54ULL) + aPhaseHOrbiterUpdateSaltE[((aIndex + 3U)) & S_SALT1];
            aOrbiterE = (aOrbiterE ^ aOrbiterK) ^ 0x7DADB0CE55CADE49ULL;
            aOrbiterE = RotL64((aOrbiterE * 0xB89C5DD075779549ULL), 51U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterK) + 0x7143419017BFBFABULL;
            aOrbiterD = (aOrbiterD ^ aOrbiterJ) ^ 0x0EEC6041D14F2D1AULL;
            aOrbiterD = RotL64((aOrbiterD * 0x8DE03EBEC3BAF987ULL), 47U);
            //
            aOrbiterB = ((aOrbiterB + aOrbiterH) + 0x2C0DE3747E9695CDULL) + aPhaseHOrbiterUpdateSaltB[(((31U - aIndex) + 6U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterB) ^ 0xDA6CF3CE053342A3ULL;
