            //
            aOrbiterG = (aOrbiterG + aOrbiterB) + 0xA3D57A8A7F0AF281ULL;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterG) ^ 0x2ADCB5296D53B25FULL;
            aOrbiterJ = RotL64((aOrbiterJ * 0x41AF5385BC466E2DULL), 19U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterD) + 0xDD2D7CB317445C7DULL;
            aOrbiterB = (aOrbiterB ^ aOrbiterC) ^ 0xF6E53C93A326B0A7ULL;
            aOrbiterB = RotL64((aOrbiterB * 0xD6877B069917CB7DULL), 57U);
            //
            aOrbiterH = ((aOrbiterH + aOrbiterG) + 0x725BF1DA16067C08ULL) + aPhaseHOrbiterUpdateSaltC[(((31U - aIndex) + 10U)) & S_SALT1];
